import{_ as i,o as s,c as n,ag as a}from"./chunks/framework.DjDv_3Bc.js";const t="/290-datenbanken/assets/insert-erklaerung.CtrmjYxT.png",c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"projekt/thema-2-insert.md","filePath":"content/projekt/Thema 2 - Insert.md","lastUpdated":1777581665000}'),l={name:"projekt/thema-2-insert.md"};function r(h,e,p,d,k,o){return s(),n("div",null,[...e[0]||(e[0]=[a(`<h2 id="thema-2-–-daten-einfullen" tabindex="-1">Thema 2 – Daten einfüllen <a class="header-anchor" href="#thema-2-–-daten-einfullen" aria-label="Permalink to &quot;Thema 2 – Daten einfüllen&quot;">​</a></h2><h3 id="auftrag" tabindex="-1">Auftrag <a class="header-anchor" href="#auftrag" aria-label="Permalink to &quot;Auftrag&quot;">​</a></h3><p>Fülle deine Datenbank mit sinnvollen Daten:</p><ul><li><strong>2 Haupttabellen</strong> mit je mindestens <strong>15 Einträgen</strong></li><li><strong>Alle anderen Tabellen</strong> mit je mindestens <strong>5 Einträgen</strong></li></ul><p>Dokumentiere einen Beispielbefehl und beschreibe in 1–2 Sätzen, wann dieser Befehl verwendet wird.</p><h3 id="was-ist-insert" tabindex="-1">Was ist INSERT? <a class="header-anchor" href="#was-ist-insert" aria-label="Permalink to &quot;Was ist INSERT?&quot;">​</a></h3><p>Mit <code>INSERT</code> fügen wir neue Zeilen in eine Tabelle ein. Das ist der Befehl, den wir brauchen, um unsere Datenbank mit Daten zu füllen.</p><p><strong>Beispiel:</strong> Ein neues Produkt einfügen:</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">INSERT INTO</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> produkte (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, preis)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">VALUES</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Kaffee&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">50</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p><img src="`+t+`" alt="Erklärung INSERT"></p><p>Was passiert hier?</p><ul><li><code>INSERT INTO produkte</code> – wir fügen eine neue Zeile in die Tabelle <code>produkte</code> ein</li><li><code>(name, preis)</code> – das sind die Spalten, die wir befüllen</li><li><code>VALUES (&#39;Kaffee&#39;, 3.50)</code> – das sind die Werte, die wir eintragen</li></ul><blockquote><p>💡 Die Reihenfolge der Werte muss mit der Reihenfolge der Spalten übereinstimmen. <code>name</code> bekommt <code>&#39;Kaffee&#39;</code>, <code>preis</code> bekommt <code>3.50</code>.</p></blockquote><blockquote><p>💡 Die Spalte <code>id</code> müssen wir nicht angeben, da sie automatisch generiert wird. Wir haben sie als <code>Serial</code> definiert.</p></blockquote><h3 id="mehrere-eintrage-auf-einmal" tabindex="-1">Mehrere Einträge auf einmal <a class="header-anchor" href="#mehrere-eintrage-auf-einmal" aria-label="Permalink to &quot;Mehrere Einträge auf einmal&quot;">​</a></h3><p>Es wäre mühsam, 15 Einträge einzeln einzutippen. Wir können mehrere Zeilen mit einem einzigen Befehl einfügen:</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">INSERT INTO</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> produkte (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, preis)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">VALUES</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  (</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Kaffee&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">50</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  (</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Tee&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">90</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">),</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  (</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Wasser&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">50</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><p>Jede Zeile nach <code>VALUES</code> ist ein neuer Eintrag. Die Zeilen werden mit einem Komma getrennt, der letzte Eintrag endet mit einem Semikolon <code>;</code>.</p><h3 id="schritt-fur-schritt" tabindex="-1">Schritt für Schritt <a class="header-anchor" href="#schritt-fur-schritt" aria-label="Permalink to &quot;Schritt für Schritt&quot;">​</a></h3><blockquote><p>Wo füllen wir 5 ein und wo 15? Das musst du selber entscheiden. Überlege dir, wo es sinnvoll ist, 15 Einträge zu haben und wo 5.</p></blockquote><p><strong>Schritt 1:</strong> Schau dir deine Tabellen an. Welche Spalten hat die Tabelle? Welche Spalten musst du befüllen?</p><blockquote><p>💡 Du weisst nicht mehr, wie deine Tabellen und Spalten heissen? <a href="/290-datenbanken/projekt/sql-tool#meine-tabellen">Hier nachschauen.</a></p></blockquote><p><strong>Schritt 2:</strong> Schreibe einen INSERT Befehl nach diesem Muster:</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">INSERT INTO</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> tabellenname (spalte1, spalte2, spalte3)</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">VALUES</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  (wert1, wert2, wert3),</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  (wert1, wert2, wert3);</span></span></code></pre></div><p><strong>Schritt 3:</strong> Teste es im Query Editor mit <strong>Run Query</strong>. Erscheint keine Fehlermeldung? Dann hat es geklappt.</p><p><strong>Schritt 4:</strong> Überprüfe deine Einträge mit einem schnellen SELECT:</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> tabellenname;</span></span></code></pre></div><p>Siehst du deine neuen Einträge? Perfekt!</p><p><strong>Schritt 5:</strong> Wiederhole das für alle deine Tabellen, bis du die geforderte Anzahl Einträge erreicht hast.</p><h3 id="tipp-ki-verwenden" tabindex="-1">Tipp: KI verwenden <a class="header-anchor" href="#tipp-ki-verwenden" aria-label="Permalink to &quot;Tipp: KI verwenden&quot;">​</a></h3><p>15 Einträge von Hand erfinden ist aufwändig. Du kannst eine KI wie ChatGPT bitten, dir die Daten zu generieren. Zum Beispiel:</p><blockquote><p><em>„Generiere mir 15 INSERT Befehle für eine SQL Tabelle <code>produkte</code> mit den Spalten <code>name</code> (Text) und <code>preis</code> (Float).&quot;</em></p></blockquote><p>Kopiere die generierten Befehle in den Query Editor und führe sie aus.</p><hr><p>✅ Dokumentiere einen Beispielbefehl aus deinem Projekt und beschreibe in 1–2 Sätzen, was er macht und wann er verwendet wird.</p>`,35)])])}const g=i(l,[["render",r]]);export{c as __pageData,g as default};
